#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Find the TRUE enrichment throughput signal (exit-0-safe): which atlas.business timestamp
column advances, the enrich workers' own REPORT rate from journals, and what the async
worker is actually doing. Identifies the right metric to wire into metrics-live."""
import os,sys,json,time,subprocess
def psql(q,t=18):
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc","SET statement_timeout='12s'; "+q],capture_output=True,text=True,timeout=t)
    return (r.stdout.strip().split('\n')[-1] if r.returncode==0 and r.stdout.strip() else None)
def sh(c,t=20):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "ERR"
out={"kind":"truerate","ts":int(time.time())}
try:
    # timestamp columns on atlas.business
    cols=psql("SELECT string_agg(column_name,',') FROM information_schema.columns WHERE table_schema='atlas' AND table_name='business' AND (data_type LIKE 'timestamp%' OR column_name ~ '_at$|updated|enriched|checked')")
    out["ts_cols"]=cols
    rates={}
    for c in (cols.split(',') if cols else []):
        c=c.strip()
        if not c: continue
        n=psql("SELECT count(*) FROM atlas.business WHERE %s > now()-interval '300 seconds'"%c)
        if n is not None: rates[c]=n+" in 5min (=%s/min)"%(round(int(n)/5,1) if n.isdigit() else '?')
    out["business_recent_by_col"]=rates
    # enrich_queue timestamp cols + recent
    qcols=psql("SELECT string_agg(column_name,',') FROM information_schema.columns WHERE table_schema='atlas' AND table_name='enrich_queue'")
    out["queue_cols"]=qcols
    for c in ['done_at','finished_at','updated_at','completed_at']:
        if qcols and c in qcols.split(','):
            n=psql("SELECT count(*) FROM atlas.enrich_queue WHERE %s > now()-interval '60 seconds'"%c)
            out["queue_%s_per_min"%c]=n
    # workers' own REPORT lines (sync pool)
    out["pool_reports"]=sh("for i in 1 2 3; do journalctl -u atlas-enrich-pool@$i.service --since '120 sec ago' --no-pager 2>/dev/null | grep -iE 'REPORT|rate=|enriched' | tail -1; done")
    # async worker activity
    out["async_journal"]=sh("journalctl -u atlas-enrich-async@1.service --since '120 sec ago' --no-pager 2>/dev/null | tail -8")
    out["async_batch_journal"]=sh("journalctl -u atlas-enrich-async-batch@1.service --since '120 sec ago' --no-pager 2>/dev/null | tail -6")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/truerate.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"truerate","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
